import { useState } from "react";
import { TreeCanvas } from "../../components/tree/TreeCanvas";
import type { TreeNode } from "../../components/tree/types";
import { GraphToolbar, useGraphFilter, defaultGraphFilter } from "../../components/graph";
import { initialTree } from "./data";
import { treeConfig } from "./config";
import { usePanelRunbookTreeHandlers } from "./handlers";

/**
 * PanelRunbookTree — a fully-typed, self-contained tree with a search / sort /
 * filter toolbar above the canvas.
 *
 * Drop into any page:
 *   <PanelRunbookTree />
 *
 * To plug into a backend, edit the handlers in `./handlers.ts`. To remove the
 * toolbar, delete the `GraphToolbar`/`useGraphFilter` wiring below and set
 * `showToolbar: false` in `./config.ts`.
 */
export function PanelRunbookTree() {
  const [tree, setTree] = useState<TreeNode>(initialTree);
  const [filter, setFilter] = useState(defaultGraphFilter);
  const { handleNodeAdd, handleNodeUpdate, handleNodeRemove, handleNodeMove } = usePanelRunbookTreeHandlers();
  const { tree: filteredTree, matches, stats, allTags } = useGraphFilter(tree, filter);

  return (
    <div className="flex flex-col gap-2">
      <GraphToolbar
        filter={filter}
        onChange={setFilter}
        allTags={allTags}
        matched={stats.matched}
        total={stats.total}
      />
      <TreeCanvas
        config={treeConfig}
        tree={filter.mode === "hide" ? filteredTree : tree}
        onTreeChange={setTree}
        highlightIds={filter.mode === "dim" ? matches : undefined}
        onNodeAdd={handleNodeAdd}
        onNodeUpdate={handleNodeUpdate}
        onNodeRemove={handleNodeRemove}
        onNodeMove={handleNodeMove}
      />
    </div>
  );
}

import type { TreeCanvasConfig } from "../../components/tree/types";

/** Static configuration. All fields are typed and validated. */
export const treeConfig: TreeCanvasConfig = {
  "title": "Incident Runbook",
  "layout": "vertical",
  "editable": true,
  "draggable": true,
  "connector": "stepped",
  "panZoom": true,
  "background": "grid",
  "siblingGap": 28,
  "levelGap": 80,
  "minHeight": 500
};

import type { TreeNode } from "../../components/tree/types";

/** Initial tree data. Swap with your own backend fetch when wiring up production. */
export const initialTree: TreeNode = {
  "id": "incident",
  "label": "Incident Declared",
  "meta": {
    "badge": "P1",
    "color": "hsl(0 84% 60%)"
  },
  "children": [
    {
      "id": "detect",
      "label": "1. Detect & confirm",
      "meta": {
        "action": {
          "kind": "panel",
          "title": "Detect & confirm",
          "body": "Check Datadog SLO dashboards. Confirm alert isn't a false positive by correlating two independent signals."
        }
      },
      "children": [
        {
          "id": "page",
          "label": "2. Page on-call",
          "meta": {
            "action": {
              "kind": "panel",
              "title": "Page on-call",
              "body": "Use PagerDuty. Escalate to L2 after 5 min if no ack."
            }
          },
          "children": [
            {
              "id": "mitigate",
              "label": "3. Mitigate",
              "meta": {
                "action": {
                  "kind": "panel",
                  "title": "Mitigate",
                  "body": "Revert latest deploy, drain affected pods, or flip feature flag — whichever is cheapest to undo."
                }
              },
              "children": [
                {
                  "id": "postmortem",
                  "label": "4. Postmortem",
                  "meta": {
                    "color": "hsl(160 84% 39%)",
                    "action": {
                      "kind": "panel",
                      "title": "Postmortem",
                      "body": "Write within 48h. Blameless. Include timeline, contributing factors, and 3 action items."
                    }
                  }
                }
              ]
            }
          ]
        }
      ]
    }
  ]
};

import { useCallback } from "react";
import type {
  TreeNodeAddEvent,
  TreeNodeUpdateEvent,
  TreeNodeRemoveEvent,
  TreeNodeMoveEvent,
} from "../../components/tree/types";

/**
 * One handler per mutation — wire each to your backend.
 */
export function usePanelRunbookTreeHandlers() {
  const handleNodeAdd = useCallback((event: TreeNodeAddEvent) => {
    console.log("[tree] node added", event);
  }, []);

  const handleNodeUpdate = useCallback((event: TreeNodeUpdateEvent) => {
    console.log("[tree] node updated", event);
  }, []);

  const handleNodeRemove = useCallback((event: TreeNodeRemoveEvent) => {
    console.log("[tree] node removed", event);
  }, []);

  const handleNodeMove = useCallback((event: TreeNodeMoveEvent) => {
    console.log("[tree] node moved", event);
  }, []);

  return { handleNodeAdd, handleNodeUpdate, handleNodeRemove, handleNodeMove };
}
